var NPCS={
  brenna:{name:'Brenna',loc:'market',icon:'🧑‍🌾',title:'Market Keeper',
    portrait:{bg:['#5a7247','#3d5230'],ring:'#8aaa70',accent:'#c4956a'},
    lines:['"Cindervale used to be something, you know. Before the Heartforge went cold. I still remember the light from the vents."','"Ashbloom and Hearthstone — that\'s how every good alchemist starts. Simple ingredients, simple cures, honest work."','"The Cinderfolk bring ore, the Ashwardens keep watch, and I keep everyone fed and supplied. That\'s how a village works."','"My grandmother ran this stall before me. Said the Market was the heart of Cindervale, even more than the Forge."','"You\'re different from the last alchemist who came through. They didn\'t stay. I have a feeling you will."']},
  tarn:{name:'Tarn',loc:'chapel',icon:'🧙',title:'Runekeeper · Veilwalker Elder',
    portrait:{bg:['#2d2450','#1a1535'],ring:'#7b68c4',accent:'#9b7fc4'},
    lines:['"The Heartforge sleeps, but it dreams. I can feel it through the stone some nights."','"The Veilwalkers have kept watch for three generations. Waiting for someone who could brew the Catalyst."','"Knowledge is fragile. One lost recipe, one forgotten technique, and the whole chain breaks."','"The Veil between worlds is thinner here than anywhere else. That\'s what makes Cindervale special — and dangerous."','"I\'ve read every text in the archive. The answer is always the same: the Heartforge must burn again."']},
  holst:{name:'Holst',loc:'chapel',icon:'⚔️',title:'Captain of the Ashwardens',
    portrait:{bg:['#5c2020','#3a1515'],ring:'#cc5544',accent:'#cc5544'},
    lines:['"The vents are more active every season. Something down there is waking up, and my soldiers are the only thing between it and this village."','"Ironhide saves lives. I\'ve seen a potion turn a killing blow into a bad bruise. Never underestimate good alchemy."','"The Ashwardens don\'t give trust easily. We earn it in blood and ash. But those who earn it find us loyal to the last."','"I was born in Cindervale. I\'ll die here too, if that\'s what it takes. But I\'d rather live to see it bloom again."']},
  marta:{name:'Marta',loc:'tavern',icon:'🍺',title:'Tavern Keeper · Hearthkeeper',
    lines:['"Part tavern, part chapel — that\'s how we do things in Cindervale. A warm drink and a warm prayer go hand in hand."','"My niece Wren has nimble fingers. If you need help in the workshop, she\'d love the work."','"The Ember & Anvil has stood since before the Heartforge went cold. These walls have stories in them."','"Keep the faith, alchemist. Cindervale has survived worse than this. Probably."']},
  gretta:{name:'Gretta',loc:'chapel',icon:'⛏️',title:'Cinderfolk Guild Representative',
    portrait:{bg:['#4a4040','#2e2828'],ring:'#aa8866',accent:'#aa8866'},
    lines:['"The deep mines hold more than ore. There are crystals down there that sing if you listen right."','"Earn the Cinderfolk\'s trust and we\'ll show you veins that haven\'t been touched in fifty years."','"Mining is honest work. You put in effort, the stone gives back. Simple as that."','"My crew pulled a Deep Crystal last week — first one in months. The deep veins are coming alive again."']},
  // ═══ ASHFALL CROSSING NPCs ═══
  sola:{name:'Sola',loc:'market',icon:'💂',title:'Caravan Guard Captain',
    portrait:{bg:['#6a5a30','#4a3a20'],ring:'#c0a040',accent:'#d0b060'},
    lines:['"The desert takes everything that isn\'t bolted down. Including people, if you\'re not careful."','"I\'ve run caravans across the Scorchlands for fifteen years. Lost count of the sandstorms."','"A good alchemist is worth ten guards out here. Potions keep my people alive."','"Ashfall Crossing is rough, but it\'s honest. Everyone here earned their place."']},
  razak:{name:'Razak',loc:'market',icon:'⚒️',title:'Guild Weaponsmith',
    portrait:{bg:['#4a3a3a','#2e2020'],ring:'#c06040',accent:'#d08060'},
    lines:['"Obsidian-edged blades. That\'s what the Guild wants. That\'s what I make."','"Your oils make the difference between a blade that cuts and a blade that shatters."','"The Sand Merchants Guild controls every trade route through the crossing. Best to stay on their good side."','"I\'ve been smithing since before you were born, alchemist. But I can\'t do it without good reagents."']},
  amara:{name:'Amara',loc:'chapel',icon:'🕯️',title:'Flamekeeper High Priestess',
    portrait:{bg:['#5a2a1a','#3a1a0a'],ring:'#d06030',accent:'#ff8040'},
    lines:['"The Sacred Flame has burned since the founding. It will burn long after we are dust."','"Pilgrims come from across the desert seeking healing. We turn no one away."','"The Flamekeepers remember. We remember the old ways, the old recipes, the old promises."','"Your craft serves the flame, alchemist. Every potion you brew is a prayer answered."']},
  tarek:{name:'Tarek',loc:'tavern',icon:'🧭',title:'Dustwalker Pathfinder',
    portrait:{bg:['#4a4030','#2e2a1a'],ring:'#8a7050',accent:'#a09060'},
    lines:['"The desert has paths. You just need to know where to look."','"My scouts mapped every dune, every canyon, every oasis within fifty leagues."','"The Dustwalkers don\'t fight the desert. We move with it. That\'s how we survive."','"There are ruins out there older than any kingdom. The Buried Temple is just the beginning."']},
  nahla:{name:'Nahla',loc:'chapel',icon:'📜',title:'Temple Scholar & Archaeologist',
    portrait:{bg:['#3a3050','#1e1830'],ring:'#9080b0',accent:'#b0a0d0'},
    lines:['"Every grain of sand in the Crossing tells a story. You just need the patience to listen."','"The Buried Temple predates every civilization we know. Who built it? That\'s what I intend to find out."','"I\'ve catalogued over three hundred inscriptions. Less than a tenth have been translated."','"Alchemy and archaeology share a common ancestor — the desire to transform what we find into what we need."']},
  // ═══ TIDECREST HARBOR NPCs ═══
  reva:{name:'Reva',loc:'tavern',icon:'⚓',title:'Harbor Guard Captain',
    portrait:{bg:['#3a4a5a','#1e2a3a'],ring:'#6090b0',accent:'#80b0d0'},
    lines:['"I was a corsair once. Then I saw what they did to a fishing village. Changed sides that same day."','"The harbor runs on trust. You break that trust, you answer to me."','"A good alchemist keeps my guards alive. I don\'t forget that."','"These cliffs have watched a thousand ships come and go. Most of them honestly."']},
  mako:{name:'Mako',loc:'market',icon:'🤿',title:'Pearl Diver Elder',
    portrait:{bg:['#2a4a4a','#1a3030'],ring:'#40a0a0',accent:'#60c0c0'},
    lines:['"The reef has moods. Some days it gives freely. Others it takes back everything."','"I\'ve been diving since I could hold my breath. Sixty years. The sea still surprises me."','"Pearl Divers don\'t compete. What we find, we share. That\'s how we\'ve survived."','"The Coral Labyrinth holds things no one has ever catalogued. You interested?"']},
  sister_coral:{name:'Sister Coral',loc:'chapel',icon:'🌊',title:'Tidekeeper Priestess',
    portrait:{bg:['#2a3a5a','#1a2040'],ring:'#5070a0',accent:'#7090c0'},
    lines:['"The tides carry messages. You just have to learn to read them."','"The Drowned Sanctum was a temple before it sank. The Tidekeepers remember what was worshipped there."','"Water cleanses, water heals, water destroys. All three are sacred."','"Brew with the tide, not against it. Your potions will be stronger for it."']},
  finn:{name:'Finn',loc:'market',icon:'⚗️',title:'Ship\'s Alchemist',
    portrait:{bg:['#3a5040','#2a3a30'],ring:'#70a080',accent:'#90c0a0'},
    lines:['"I was the alchemist on the Stormchaser. Two years at sea. You learn to brew with what the ocean gives you."','"Kelp, coral, barnacle — most people see trash. I see ingredients."','"The merchant fleet needs potions for scurvy, sea sickness, pressure sickness... always more demand than supply."','"One day I\'ll brew something that lets you breathe underwater. I\'m close, I can feel it."']},
  old_anchor:{name:'Old Anchor',loc:'tavern',icon:'🏴',title:'Retired Smuggler & Barkeep',
    portrait:{bg:['#4a3a2a','#2e2418'],ring:'#a08060',accent:'#c0a080'},
    lines:['"Everyone who passes through Tidecrest ends up at my bar eventually. That\'s how I know everything."','"I smuggled for twenty years. Gems, potions, the occasional fugitive. Now I just serve drinks."','"The Corsairs used to leave the harbor alone. Something changed. Something down in the deep."','"Need a contact? A rumor? A very strong drink? I can help with all three."']},

  // ═══ SKYREACH NPCs ═══
  sr_kael:{id:'sr_kael',name:'Kael Windforge',icon:'👨‍🦳',loc:'market',title:'Mountain Trader',
    portrait:{bg:['#4a5a6a','#2a3a4a'],ring:'#6080a0'},
    lines:['"The wind doesn\'t care about your plans. Neither do I. What do you need?"','"Everything costs more up here. That\'s the price of altitude."','"I\'ve been trading on this peak for thirty years. I know every herb and every trail."'],},
  sr_lira:{id:'sr_lira',name:'Lira Cloudwhisper',icon:'🧝‍♂️',loc:'tavern',title:'Meteorologist',
    portrait:{bg:['#3a4a5a','#1e2a3a'],ring:'#50808a'},
    lines:['"The barometric pressure suggests... ah, never mind. How can I help?"','"Storm\'s coming in from the west. Three hours, maybe four."','"The weather up here tells stories, if you know how to listen."'],},
  sr_bron:{id:'sr_bron',name:'Old Bron Stonefoot',icon:'👴',loc:'tavern',title:'Retired Scout',
    portrait:{bg:['#5a4a3a','#3a2a1a'],ring:'#a09070'},
    lines:['"Did I ever tell you about the time I climbed the Zenith in a blizzard?"','"Sit down, sit down. Let me tell you about the Sky Ruins."','"The mountain teaches patience. Also frostbite. Mostly frostbite."'],},
  sr_yuki:{id:'sr_yuki',name:'Yuki Starsight',icon:'🧑‍🏫',loc:'tavern',title:'Starcaller Initiate',
    portrait:{bg:['#3a3a5a','#1e1e3a'],ring:'#6060a0'},
    lines:['"I\'ve been translating the runes and... sorry, you probably don\'t care."','"The observatory instruments still work! After all this time!"','"Do you ever wonder who built the Sky Ruins? I think about it constantly."'],},
  sr_mika:{id:'sr_mika',name:'Mika the Wind',icon:'🧒',loc:'tavern',title:'Local Gossip',
    portrait:{bg:['#4a5040','#2a3020'],ring:'#808a60'},
    lines:['"I heard something! Want to know?"'],
    gossip:true,
    flavor:['"They say the Starcallers found a new star — one that wasn\'t there last month."','"A Windrunner came back from the Observatory missing two days of memory."','"The Cloud Traders are charging triple for rope. Something about the Stairway shifting."','"Old Bron claims he saw lights in the Sky Ruins at midnight. Moving lights."','"The Gale took another hundred feet of the western pass last night."','"Eclipse Covenant markings on the Stormspire. Fresh ones."','"There\'s a glacier flower that blooms only when the aurora is green."','"Kael keeps a locked chest under the counter. Nobody knows what\'s in it."']},
};
