var genBoardQuests=(level,day,bonusQuests=0,loc='cindervale',knownRecipes=[])=>{
  const n=2+Math.floor(Math.random()*2)+bonusQuests; // 2-3 quests + bonus
  const avail=BQ_TEMPLATES.filter(t=>level>=t.minLv&&(!t.loc||t.loc===loc));
  if(avail.length===0)return[];
  // Build set of locally available ingredients for recipe craftability check
  const locIngrSet=new Set();
  REGIONS.filter(r=>r.loc===loc).forEach(r=>r.ingr.forEach(i=>locIngrSet.add(i)));
  const canCraftHere=(recipeId)=>{const r=RECIPES.find(x=>x.id===recipeId);return r&&!r.buff&&r.ingr.every(id=>locIngrSet.has(id)||locIngrSet.has(locIngr(id,loc)));};
  const isKnownHere=(recipeId)=>knownRecipes.includes(recipeId)&&canCraftHere(recipeId);  const locFactions=loc==='tidecrest'?['harbormasters','pearl_divers','tidekeepers','merchant_marine']:loc==='ashfall'?['sand_merchants','flamekeepers','dustwalkers']:loc==='skyreach'?['skywardens','starcallers','cloud_traders','windrunners']:['hearthkeepers','ashwardens','veilwalkers','cinderfolk'];
  const quests=[];var usedGivers=[];
  for(let i=0;i<n;i++){
    // For deliver templates, filter pool to locally craftable recipes
    let tmpl,localPool;
    let attempts=0;
    do{
      tmpl=avail[Math.floor(Math.random()*avail.length)];
      if(tmpl.type==='deliver'){localPool=tmpl.pool.filter(isKnownHere);}
      else{localPool=tmpl.pool;}
      attempts++;
    }while(localPool.length===0&&attempts<20);
    if(localPool.length===0)continue;
    const giverPool=BQ_GIVERS_BY_LOC[loc]||BQ_GIVERS;
    let giver;do{giver=giverPool[Math.floor(Math.random()*giverPool.length)];}while(usedGivers.includes(giver));
    usedGivers.push(giver);
    const itemId=localPool[Math.floor(Math.random()*localPool.length)];
    const qty=tmpl.qtyR[0]+Math.floor(Math.random()*(tmpl.qtyR[1]-tmpl.qtyR[0]+1))+Math.floor(level/5);
    const isPotion=tmpl.type==='deliver';
    const r=isPotion?RECIPES.find(x=>x.id===itemId):null;
    const ing=!isPotion?INGR[itemId]:null;
    const itemName=r?r.name:ing?.name||itemId;
    const itemIcon=r?r.icon:ing?.icon||'';
    const gold=qty*tmpl.gPer+Math.floor(level*1.5);
    const xpR=qty*tmpl.xPer+level*3;
    const faction=locFactions[Math.floor(Math.random()*locFactions.length)];
    const fRep=5+tmpl.tier*3;
    const desc=tmpl.descs[Math.floor(Math.random()*tmpl.descs.length)]
      .replace(/\{qty\}/g,qty).replace(/\{itemName\}/g,itemName).replace(/\{s\}/g,qty>1?'s':'');
    quests.push({id:'bq_'+day+'_'+i,type:tmpl.type,target:itemId,count:qty,giver,
      name:giver+': '+qty+'× '+itemIcon+itemName,desc,gold,xp:xpR,faction,fRep,
      itemName,itemIcon,tier:tmpl.tier});
  }
  return quests;
};

